extends Node

## NPC Schedule Manager — drives daily routines for registered NPCs.

signal npc_state_changed(npc_name: String, state: String, location: String)
signal npc_arrived_at_waypoint(npc_name: String, waypoint: String)

enum NPCState { ASLEEP, IDLE, PATROL, TRAVELING, WORKING }

@export var waypoint_speed: float = {{waypoint_speed}}
@export var idle_time_min: float = {{idle_time_min}}
@export var idle_time_max: float = {{idle_time_max}}
@export var arrival_threshold: float = {{arrival_threshold}}

var _npcs: Dictionary = {}  ## npc_name → {node, schedule, state, current_task}
var _day_night_manager: Node = null
var _waypoints: Dictionary = {}  ## waypoint_name → Node3D

func _ready():
	call_deferred("_init_system")

func _process(_delta: float) -> void:
	if _day_night_manager == null:
		return

	var time := _day_night_manager.get_time_of_day()
	for npc_name in _npcs:
		_update_npc(npc_name, time)

func register_npc(npc: Node3D, schedule_id: String) -> bool:
	"""Register a CharacterBody3D or Node3D with a schedule."""
	var schedule := _load_schedule(schedule_id)
	if schedule.is_empty():
		push_error("Schedule not found: %s" % schedule_id)
		return false

	_npcs[npc.name] = {
		"node": npc,
		"schedule": schedule,
		"state": NPCState.IDLE,
		"current_entry": "",
		"idle_timer": 0.0,
		"target_pos": Vector3.ZERO,
		"current_path": PackedVector3Array(),
		"path_index": 0,
	}
	return true

func unregister_npc(npc_name: String) -> void:
	_npcs.erase(npc_name)

func register_waypoint(waypoint: Node3D) -> void:
	_waypoints[waypoint.name] = waypoint

func get_npc_state(npc_name: String) -> int:
	if not _npcs.has(npc_name):
		return -1
	return _npcs[npc_name].state

func get_npc_location(npc_name: String) -> String:
	if not _npcs.has(npc_name):
		return ""
	return _npcs[npc_name].current_entry

func force_npc_to_location(npc_name: String, location: String) -> void:
	if not _npcs.has(npc_name):
		return
	var npc_data := _npcs[npc_name]
	if _waypoints.has(location):
		npc_data.node.global_position = _waypoints[location].global_position
		npc_data.current_entry = location
		_set_npc_state(npc_name, NPCState.IDLE)

func _init_system() -> void:
	_day_night_manager = get_tree().get_first_node_in_group("day_night")
	# Scan for waypoint nodes
	_scan_waypoints()

func _scan_waypoints() -> void:
	var parent_node := get_parent()
	_scan_node_for_waypoints(parent_node)

func _scan_node_for_waypoints(node: Node) -> void:
	for child in node.get_children():
		if child.is_in_group("waypoint"):
			_waypoints[child.name] = child
		_scan_node_for_waypoints(child)

func _load_schedule(schedule_id: String) -> Dictionary:
	var path := "{{schedule_data_path}}%s.json" % schedule_id
	var file := FileAccess.open(path, FileAccess.READ)
	if file == null:
		return {}
	var json := JSON.new()
	var err := json.parse(file.get_as_text())
	file.close()
	if err != OK:
		return {}
	return json.get_data()

func _update_npc(npc_name: String, time: float) -> void:
	var npc_data := _npcs[npc_name]
	var schedule := npc_data.schedule

	# Find the active schedule entry for current time
	var entries := schedule.get("entries", [])
	var active_entry := _find_active_entry(entries, time)

	if active_entry.is_empty():
		return

	var entry_location := active_entry.get("location", "")
	var entry_state := active_entry.get("state", "idle")

	if entry_location != npc_data.current_entry:
		_travel_to(npc_name, entry_location, entry_state)
	elif npc_data.state != _state_from_string(entry_state):
		_set_npc_state(npc_name, _state_from_string(entry_state))

	# Process movement and idle
	_process_movement(npc_name)
	_process_idle(npc_name)

func _find_active_entry(entries: Array, time: float) -> Dictionary:
	# Entries define time ranges like: { from: 0.25, to: 0.75, location: "town_square", state: "idle" }
	for entry in entries:
		var from_time := entry.get("from", 0.0)
		var to_time := entry.get("to", 1.0)
		if time >= from_time and time < to_time:
			return entry
	return {}

func _travel_to(npc_name: String, location: String, target_state: String) -> void:
	var npc_data := _npcs[npc_name]

	if not _waypoints.has(location):
		push_warning("Unknown waypoint: %s" % location)
		return

	_set_npc_state(npc_name, NPCState.TRAVELING)
	npc_data.current_entry = location
	npc_data.target_pos = _waypoints[location].global_position
	npc_data.current_path = PackedVector3Array()
	npc_data.path_index = 0

func _process_movement(npc_name: String) -> void:
	var npc_data := _npcs[npc_name]
	if npc_data.state != NPCState.TRAVELING and npc_data.state != NPCState.PATROL:
		return

	var node: Node3D = npc_data.node
	var target := npc_data.target_pos
	var dist := node.global_position.distance_to(target)

	if dist <= arrival_threshold:
		node.global_position = target
		if npc_data.state == NPCState.TRAVELING:
			npc_arrived_at_waypoint.emit(npc_name, npc_data.current_entry)
			_set_npc_state(npc_name, NPCState.IDLE)
		return

	var direction := (target - node.global_position).normalized()
	node.global_position += direction * waypoint_speed * get_process_delta_time()

	# Face movement direction
	if direction.length() > 0.01:
		var look_target := node.global_position + direction
		node.look_at(Vector3(look_target.x, node.global_position.y, look_target.z))

func _process_idle(npc_name: String) -> void:
	var npc_data := _npcs[npc_name]
	if npc_data.state != NPCState.IDLE:
		return
	npc_data.idle_timer += get_process_delta_time()

func _set_npc_state(npc_name: String, state: int) -> void:
	var npc_data := _npcs[npc_name]
	if npc_data.state == state:
		return

	var prev := npc_data.state
	npc_data.state = state
	npc_data.idle_timer = 0.0

	# Update animation
	var anim_label := _state_animation(state)
	if npc_data.node.has_method("set_animation"):
		npc_data.node.set_animation(anim_label)

	npc_state_changed.emit(npc_name, _state_name(state), npc_data.current_entry)

func _state_from_string(s: String) -> int:
	match s.to_lower():
		"asleep", "sleep":
			return NPCState.ASLEEP
		"patrol", "walk":
			return NPCState.PATROL
		"work":
			return NPCState.WORKING
		_:
			return NPCState.IDLE

func _state_name(state: int) -> String:
	match state:
		NPCState.ASLEEP: return "asleep"
		NPCState.IDLE: return "idle"
		NPCState.PATROL: return "patrol"
		NPCState.TRAVELING: return "traveling"
		NPCState.WORKING: return "working"
	return "unknown"

func _state_animation(state: int) -> String:
	match state:
		NPCState.ASLEEP: return "sleep"
		NPCState.IDLE: return "idle"
		NPCState.PATROL, NPCState.TRAVELING: return "walk"
		NPCState.WORKING: return "work"
	return "idle"

func serialize() -> Dictionary:
	var data := {}
	for name in _npcs:
		var nd := _npcs[name]
		data[name] = {
			"state": nd.state,
			"current_entry": nd.current_entry,
			"pos": {"x": nd.node.global_position.x, "y": nd.node.global_position.y, "z": nd.node.global_position.z},
		}
	return data

func deserialize(data: Dictionary) -> void:
	for name in data:
		if _npcs.has(name):
			var nd := data[name]
			_npcs[name].state = nd.get("state", NPCState.IDLE)
			_npcs[name].current_entry = nd.get("current_entry", "")
			var pos := nd.get("pos", {})
			_npcs[name].node.global_position = Vector3(pos.get("x", 0), pos.get("y", 0), pos.get("z", 0))
